var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그래서… ","JPN":"それで…… ","ENG":"So...","TWN":"所以……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"관리국의 마지막 계획에 제 능력이 필요하단 말씀이군요.","JPN":"管理局の最後の計画に、私の能力が必要なんですよね。","ENG":"You are telling me that my powers are needed for the Administration's final plan.","TWN":"你是說，管理局的最後計畫需要我的力量嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"지금 이 순간에도 이 세계는 빠르게 침식되어가고 있다.","JPN":"今この瞬間にも、この世界は凄まじいスピードで侵食されている。","ENG":"Even as we speak, the Corruption is quickly spreading throughout this world.","TWN":"甚至在這一刻，這個世界也在迅速被侵蝕。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"머잖아 모든 게 뒤틀리고, 운명을 가진 것들은 이성 한 점 없는 괴물로 변하고 말겠지.","JPN":"近いうちにすべてが歪み、運命を持つすべての生き物は理性を失った化け物になり果ててしまうだろう。","ENG":"Soon, everything will be twisted, and those with fate will turn into monsters that have gone insane.","TWN":"不久之後，一切都會被扭曲，擁有命運的存在將變成毫無理性的怪物。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그렇게 노력했는데도… 마지막엔 전부 괴물이 되어야 하다니…","JPN":"あんなに頑張ったのに……最後はみんな化け物になるしかないなんて……","ENG":"We tried so hard... but in the end, they will all turn into monsters...","TWN":"明明已經那麼努力了……最後卻全都變成了怪物……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"너무 비참하네요.","JPN":"惨い話ですね。","ENG":"How dreadful.","TWN":"太淒慘了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"관리국은 방주에 필요한 모든 걸 싣고, 떠날 준비를 마쳤어.","JPN":"管理局は必要なものをすべて箱舟に乗せ、ここを離れる準備を済ませた。","ENG":"The Administration has loaded the Ark with every necessity, and is ready to depart.","TWN":"管理局已經裝載了方舟所需的一切，準備出發了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"그 자리에 인류는 없겠지만, 다음 관리국이 필요로 할 모든 정보가 다음 세계로 보내질 거다.","JPN":"そこに人類はいないが、管理局が必要とするすべての情報が、次の世界に届けられるだろう。","ENG":"Humanity might not be included there, but all the information the Administration might need will be sent to the next world.","TWN":"那裡或許不存在人類，但管理局所需要的所有資訊都會被送往下一個世界。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"그리고 난 네 능력의 도움을 받아, 내 운명을 이 세계에 남겨두기로 했다.","JPN":"そして私はお前の能力を借りて、自分の運命をこの世界に残すことにした。","ENG":"Also, I've decided to leave my fate here with the help of your ability.","TWN":"另外，我想要借助你的能力，將我的命運留在這個世界。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"제가 하고 싶지 않다고 말하면… 꿀밤을 때리실 건가요?","JPN":"私がやりたくないと言ったら……デコピンするんですか？","ENG":"If I say I don't want to do it... are you going to flick me on my forehead?","TWN":"如果我說我不想這麼做……你會敲我的頭嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"그게 네 생각을 정리하는 데 도움이 된다면, 그렇게라도 해주지.","JPN":"それでお前の頭の中が整理されるなら、そうしよう。","ENG":"If that helps you to get your head in the game, so be it.","TWN":"會的，如果那能幫你理清思緒的話。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"아하하… 농담이에요, 농담.","JPN":"あはは……冗談ですよ、冗談。","ENG":"Ah hah hah. I was joking.","TWN":"哈哈哈……我開玩笑的。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"멈춘 시간 속에서 영원히 아무 걱정 없이 지낼 기회잖아요. 제가 왜 거절하겠어요?","JPN":"止まった時間の中で、何の心配もなく過ごせるチャンスじゃないですか。断る理由などありません。","ENG":"It's an opportunity to spend an eternity without worries in frozen time. Why would I decline?","TWN":"可以在停滯的時間裡永遠無憂無慮地生活。這麼好的機會，我為什麼要拒絕呢？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"스승님의 운명엔 탐미엘을 불러들이는 저주가 있다고 하셨죠.","JPN":"師匠の運命には、タミエルを呼ぶ呪いがあると言ってましたよね。","ENG":"You said that your fate has a curse of summoning Tammiel.","TWN":"師父你的命運中有召喚塔米爾的詛咒。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"말씀하신 대로 그 운명을 이곳에 가둬두면, 다음 세계에선 그 신의 간섭을 받지 않을지도 모르겠네요.","JPN":"その運命をここに閉じ込めたら、確かに次の世界ではタミエルの干渉を受けずに済むかもしれません。","ENG":"So, if we contain that fate here like you said, maybe that god won't be able to interfere in the next world.","TWN":"正如你所說，如果將那個命運留在這裡，或許在下一個世界就不會受到那個神的干涉了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"그리 간단히 해결될 문제는 아니다.","JPN":"そう簡単にはいかないだろう。","ENG":"This isn't something that can be resolved that easily.","TWN":"不是那麼想當然的事情。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"클리포트 게임을 원하는 마왕들이 존재하는 이상, 탐미엘은 어떤 식으로든 강림하게 될 거야.","JPN":"クリフォトゲームを望む魔王たちが存在する以上、タミエルはどんな形であれ降臨する。","ENG":"As long as Demon Lords who want the Qliphoth Game exist, Tammiel will descend one way or another.","TWN":"只要有渴望逆卡巴拉遊戲的魔王存在，塔米爾就會以某種方式降臨。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"하지만 적어도, 내 운명 때문에 탐미엘의 손에 늑대가 죽는 인과만큼은… 틀림없이 사라진다.","JPN":"だが、これで私の運命のせいでオオカミがタミエルに殺される因果は……確実に消える。","ENG":"But at least, the causality of the Wolf dying in Tammiel's hands because of my fate... will be no more.","TWN":"但是至少，因為我的命運，狼死在塔米爾手中的果……就不會再重現了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"늑대를 살릴 수 있다라…","JPN":"オオカミを助けられる……","ENG":"We can save the Wolf...","TWN":"這樣可以救下狼嗎……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그거면 충분하네요.","JPN":"それで十分です。","ENG":"That's a good enough reason for me.","TWN":"那就足夠了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그녀를 살리지 못했다는 사실이… 절 계속 괴롭혔거든요.","JPN":"彼女を助けられなかったことが……私はずっと辛かった。","ENG":"I was actually tormented by the fact that... we couldn't save her.","TWN":"沒能救下她的事實……一直在折磨著我。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"전 대적자로서 완전히 실패한 줄 알았는데, 아직 기회가 남아있어서 다행이에요.","JPN":"私は自分が敵対者として完全に失敗作だと思ってたけど、まだチャンスが残っていてよかったです。","ENG":"I thought I was a complete failure of an Antagonist, but I'm glad I still have a chance.","TWN":"我以為作為敵對者的我已經徹底失敗了，幸好還有機會。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"아니야…","JPN":"違う……","ENG":"No...","TWN":"不……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"넌 네가 할 수 있는 최선을 다했어.","JPN":"お前は、お前にできる最善を尽くした。","ENG":"You did the best you could.","TWN":"你已經盡你所能了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_PAST","text":{"KOREA":"부족했던 건 내 판단이었을 뿐이니… 얼마든지 원망해라.","JPN":"私の判断が未熟だっただけだ……いくらでも恨んで構わない。","ENG":"What we lacked was my judgment... So blame me all you want.","TWN":"是我的判斷力不足……儘管埋怨我吧。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"제가 왜 스승님을 원망해요?","JPN":"どうして私が師匠を恨むんです？","ENG":"Why would I blame you, Master?","TWN":"我為什麼要埋怨你呢，師父？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"가족들을 전부 잃은 그날… 전 침식체들과 싸우다 죽으려고 했어요.","JPN":"家族を失ったあの日……私は侵食体と戦って死ぬつもりでいました。","ENG":"The day I lost my family... I tried to die by fighting the C.O.s.","TWN":"失去家人的那天……我本打算跟侵蝕體戰拼命的。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_PAST","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};